INSERT INTO questions (text, option1, option2, option3, option4, correctIndex, explanation, difficulty, subtopicTag) VALUES
  ('According to Euclid''s Division Lemma, for two positive integers a and b, which of the following is correct?', 'a = bq + r, where 0 вүӨ r < b', 'a = bq + r, where 0 < r вүӨ b', 'a = bq + r, where r > b', 'a = bq + r, where r = b', 1, 'Euclid''s Division Lemma states that for any two positive integers a and b, there exist unique non-negative integers q and r such that a = bq + r, where 0 вүӨ r < b. The remainder r is always non-negative and strictly less than the divisor b.', 'PASS', 'euclid-lemma'),
  ('In Euclid''s Division Lemma a = bq + r, what does ''q'' represent?', 'Remainder', 'Divisor', 'Quotient', 'Dividend', 3, 'In a = bq + r: ''a'' is the dividend (number being divided), ''b'' is the divisor, ''q'' is the quotient (result of division), and ''r'' is the remainder.', 'PASS', 'euclid-lemma'),
  ('When 52 is divided by 7 using Euclid''s Division Lemma, what is the remainder r?', '3', '5', '6', '4', 1, '52 = 7 Г— 7 + 3. Check: 7 Г— 7 = 49, and 49 + 3 = 52. Since 0 вүӨ 3 < 7, the remainder r = 3.', 'PASS', 'euclid-lemma'),
  ('Which of the following is the valid representation using Euclid''s Division Lemma for a = 29 and b = 6?', '29 = 6 Г— 4 + 5', '29 = 6 Г— 5 + 1', '29 = 6 Г— 3 + 11', '29 = 6 Г— 6 + 7', 1, '29 = 6 Г— 4 + 5. Check: 6 Г— 4 = 24, and 24 + 5 = 29. The remainder r = 5 satisfies 0 вүӨ 5 < 6. Option B: 6Г—5+1=31вү 29. Option C: r=11>6 (invalid). Option D: r=7>6 (invalid).', 'AVERAGE', 'euclid-lemma'),
  ('If a = 45, b = 9, and a = bq + r using Euclid''s Division Lemma, what is the value of r?', '5', '9', '1', '0', 4, '45 = 9 Г— 5 + 0. Since 45 is exactly divisible by 9, the remainder r = 0. This is a valid case вҖ” r = 0 is allowed by the condition 0 вүӨ r < 9.', 'PASS', 'euclid-lemma'),
  ('In Euclid''s Division Lemma a = bq + r, which condition must the remainder always satisfy?', 'r > b', 'r = b', '0 вүӨ r < b', 'r < 0', 3, 'The remainder r must always be non-negative and strictly less than the divisor b, i.e., 0 вүӨ r < b. r cannot equal b (option 2) because then we could increase q by 1 and make r = 0.', 'PASS', 'euclid-lemma'),
  ('When 100 is divided by 13, what are the values of q and r in Euclid''s Division Lemma?', 'q = 8, r = 4', 'q = 7, r = 9', 'q = 8, r = 6', 'q = 9, r = 3', 2, '100 = 13 Г— 7 + 9. Check: 13 Г— 7 = 91, and 91 + 9 = 100. Also 0 вүӨ 9 < 13. So q = 7 and r = 9. Option A: 13Г—8=104>100, invalid.', 'PASS', 'euclid-lemma'),
  ('Which of the following values of r is NOT possible in Euclid''s Division Lemma when b = 5?', '0', '3', '5', '4', 3, 'When b = 5, the remainder r must satisfy 0 вүӨ r < 5. So r can only be 0, 1, 2, 3, or 4. r = 5 is not possible because r must be strictly less than the divisor b.', 'PASS', 'euclid-lemma'),
  ('Euclid''s Division Lemma applies to which type of integers?', 'Only negative integers', 'Only even integers', 'Any two positive integers', 'Only prime numbers', 3, 'Euclid''s Division Lemma applies to any two positive integers a and b. There is no restriction on them being even, prime, or odd вҖ” the lemma holds universally for all positive integer pairs.', 'PASS', 'euclid-lemma'),
  ('For a = 18 and b = 4, what is the correct form using Euclid''s Division Lemma?', '18 = 4 Г— 3 + 6', '18 = 4 Г— 4 + 2', '18 = 4 Г— 5 + 2', '18 = 4 Г— 2 + 10', 2, '18 = 4 Г— 4 + 2. Check: 4 Г— 4 = 16, and 16 + 2 = 18. The remainder r = 2 satisfies 0 вүӨ 2 < 4. Option A has r=6>4 (invalid). Option C: 4Г—5=20>18 (wrong). Option D has r=10>4 (invalid).', 'AVERAGE', 'euclid-lemma'),
  ('If a = bq + r and r = 0, what can we conclude?', 'a is divisible by b', 'b is divisible by a', 'a is a prime number', 'b is a prime number', 1, 'If r = 0, then a = bq exactly. This means b divides a without a remainder, so a is divisible by b. Nothing can be concluded about primality from r = 0 alone.', 'PASS', 'euclid-lemma'),
  ('If a = 7q + r, which of the following cannot be a remainder?', '6', '7', '3', '0', 2, 'For divisor b = 7, the remainder r must satisfy 0 вүӨ r < 7. So r can be 0, 1, 2, 3, 4, 5, or 6. r = 7 is not possible because r must be strictly less than b.', 'PASS', 'euclid-lemma'),
  ('If n = 9q + r and r = 8, what is the next multiple of 9 after n?', 'n + 1', 'n + 8', 'n + 9', 'n + 10', 1, 'n = 9q + 8. The next multiple of 9 is 9(q + 1) = 9q + 9 = (9q + 8) + 1 = n + 1. Since r = 8 is the maximum possible remainder before reaching the next multiple, only 1 more is needed.', 'EXPERT', 'euclid-lemma'),
  ('If a = bq + r, where b = 11, what is the maximum possible value of r?', '10', '11', '12', '9', 1, 'The remainder r must satisfy 0 вүӨ r < b = 11. Therefore r can range from 0 to 10. The maximum possible value of r is 10, which is one less than the divisor.', 'PASS', 'euclid-lemma'),
  ('A number when divided by 11 gives quotient 6 and remainder 8. What is the number?', '66', '74', '76', '70', 2, 'Using a = bq + r: a = 11 Г— 6 + 8 = 66 + 8 = 74. Verify: 74 Г· 11 = 6 remainder 8. вң“', 'AVERAGE', 'euclid-lemma'),
  ('A number leaves remainder 5 when divided by 8. Which expression represents all such numbers?', '8q + 3', '8q + 5', '5q + 8', '8q вҲ’ 5', 2, 'Using Euclid''s Lemma a = bq + r with b = 8 and r = 5, all such numbers are of the form 8q + 5. Examples: q=1 gives 13, q=2 gives 21 вҖ” both leave remainder 5 when divided by 8.', 'AVERAGE', 'euclid-lemma'),
  ('When 245 is divided by a number b, the quotient is 8 and remainder is 5. What is b?', '25', '28', '30', '35', 3, 'Using a = bq + r: 245 = b Г— 8 + 5. So 8b = 245 вҲ’ 5 = 240. Therefore b = 240 Г· 8 = 30.', 'AVERAGE', 'euclid-lemma'),
  ('Using Euclid''s Lemma, which of the following correctly expresses 73 with divisor 9?', '73 = 9 Г— 7 + 10', '73 = 9 Г— 8 + 1', '73 = 9 Г— 9 + 2', '73 = 9 Г— 6 + 19', 2, '73 = 9 Г— 8 + 1. Check: 9 Г— 8 = 72, 72 + 1 = 73. Also 0 вүӨ 1 < 9. вң“ Option A: r=10>9 (invalid). Option C: 9Г—9+2=83вү 73. Option D: r=19>9 (invalid).', 'AVERAGE', 'euclid-lemma'),
  ('A number n when divided by 12 leaves remainder 7. What will be the remainder when (n + 5) is divided by 12?', '5', '11', '0', '12', 3, 'n = 12q + 7, so n + 5 = 12q + 12 = 12(q + 1). Since n + 5 is exactly divisible by 12, the remainder is 0.', 'EXPERT', 'euclid-lemma'),
  ('What does the Fundamental Theorem of Arithmetic state?', 'Every prime number can be written as a sum of two numbers', 'Every composite number can be expressed as a unique product of primes', 'Every integer is divisible by at least two prime numbers', 'Every number has exactly two prime factors', 2, 'The Fundamental Theorem of Arithmetic states that every composite number can be expressed as a product of prime numbers, and this factorisation is unique, except for the order in which the prime factors appear.', 'PASS', 'prime-factorisation'),
  ('What is the prime factorisation of 36?', '2 Г— 18', '4 Г— 9', '2ВІ Г— 3ВІ', '2Ві Г— 3', 3, '36 = 2 Г— 18 = 2 Г— 2 Г— 9 = 2 Г— 2 Г— 3 Г— 3 = 2ВІ Г— 3ВІ. Options A and B include non-prime factors (18 and 9 respectively), so they are not prime factorisations.', 'PASS', 'prime-factorisation'),
  ('Which of the following is the correct prime factorisation of 60?', '2ВІ Г— 3 Г— 5', '2Ві Г— 5', '2 Г— 3 Г— 10', '2ВІ Г— 15', 1, '60 = 2 Г— 2 Г— 3 Г— 5 = 2ВІ Г— 3 Г— 5. All factors are prime. Options C and D include composite factors 10 and 15 respectively, so they are not prime factorisations.', 'PASS', 'prime-factorisation'),
  ('What is the exponent of 2 in the prime factorisation of 144?', '2', '3', '4', '5', 3, '144 = 2 Г— 72 = 2ВІ Г— 36 = 2Ві Г— 18 = 2вҒҙ Г— 9 = 2вҒҙ Г— 3ВІ. The exponent of 2 is 4.', 'AVERAGE', 'prime-factorisation'),
  ('Which of the following numbers is a prime number?', '15', '21', '17', '27', 3, '17 has no factors other than 1 and itself, so it is prime. 15 = 3Г—5, 21 = 3Г—7, and 27 = 3Ві are all composite numbers.', 'PASS', 'prime-factorisation'),
  ('The prime factorisation of a number is 2Ві Г— 5ВІ. What is the number?', '40', '100', '200', '160', 3, '2Ві Г— 5ВІ = 8 Г— 25 = 200. Option B (100) = 2ВІ Г— 5ВІ, not 2Ві Г— 5ВІ. Option A (40) = 2Ві Г— 5. Always expand both bases: 2Ві = 8 and 5ВІ = 25.', 'AVERAGE', 'prime-factorisation'),
  ('According to the Fundamental Theorem of Arithmetic, the prime factorisation of any composite number is:', 'Always different for the same number', 'Unique, regardless of the order of factors', 'Not always possible', 'Only possible for even numbers', 2, 'The theorem guarantees that every composite number has exactly one prime factorisation. The order of factors may vary, but the primes and their powers are always the same вҖ” this is called uniqueness.', 'PASS', 'prime-factorisation'),
  ('What is the prime factorisation of 98?', '2 Г— 7ВІ', '2ВІ Г— 7', '2 Г— 49', '7 Г— 14', 1, '98 = 2 Г— 49 = 2 Г— 7 Г— 7 = 2 Г— 7ВІ. Options C and D include the composite numbers 49 and 14, so they are not prime factorisations.', 'PASS', 'prime-factorisation'),
  ('Which of the following is NOT a prime number?', '11', '13', '19', '27', 4, '27 = 3 Г— 3 Г— 3 = 3Ві. It has factors other than 1 and itself, making it composite. All of 11, 13, and 19 are prime as they have no divisors other than 1 and themselves.', 'PASS', 'prime-factorisation'),
  ('What is the prime factorisation of 120?', '2ВІ Г— 3 Г— 10', '2Ві Г— 3 Г— 5', '2вҒҙ Г— 5', '2ВІ Г— 5 Г— 6', 2, '120 = 2 Г— 60 = 2ВІ Г— 30 = 2Ві Г— 15 = 2Ві Г— 3 Г— 5. Options A and D include non-prime factors 10 and 6. Option C: 2вҒҙГ—5=80вү 120.', 'AVERAGE', 'prime-factorisation'),
  ('What is the prime factorisation of 180?', '2ВІ Г— 3ВІ Г— 5', '2Ві Г— 3 Г— 5', '2 Г— 3Ві Г— 5', '2ВІ Г— 3 Г— 5ВІ', 1, '180 = 2 Г— 90 = 2ВІ Г— 45 = 2ВІ Г— 9 Г— 5 = 2ВІ Г— 3ВІ Г— 5. Verify: 4 Г— 9 Г— 5 = 180. вң“', 'AVERAGE', 'prime-factorisation'),
  ('If the prime factorisation of two numbers are 2Ві Г— 3ВІ Г— 5 and 2ВІ Г— 3Ві Г— 7, what is their HCF?', '2ВІ Г— 3ВІ', '2Ві Г— 3Ві', '2ВІ Г— 3ВІ Г— 5 Г— 7', '2Ві Г— 3Ві Г— 5 Г— 7', 1, 'HCF = product of smallest powers of common prime factors. Common primes are 2 and 3 only. Smallest power of 2: min(3,2) = 2ВІ. Smallest power of 3: min(2,3) = 3ВІ. HCF = 2ВІ Г— 3ВІ = 4 Г— 9 = 36.', 'AVERAGE', 'prime-factorisation'),
  ('What is the LCM of 8, 12, and 15 using prime factorisation?', '60', '90', '120', '180', 3, '8 = 2Ві, 12 = 2ВІ Г— 3, 15 = 3 Г— 5. LCM = greatest powers of all primes = 2Ві Г— 3В№ Г— 5В№ = 8 Г— 3 Г— 5 = 120.', 'AVERAGE', 'prime-factorisation'),
  ('Two numbers have prime factorisations 2ВІ Г— 3 Г— 7 and 2 Г— 3ВІ Г— 7. What is their LCM?', '2 Г— 3 Г— 7', '2ВІ Г— 3ВІ Г— 7', '2ВІ Г— 3 Г— 7ВІ', '2ВІ Г— 3ВІ Г— 7ВІ', 2, 'LCM = greatest powers of all prime factors. Max power of 2 = 2ВІ, of 3 = 3ВІ, of 7 = 7В№. LCM = 2ВІ Г— 3ВІ Г— 7 = 4 Г— 9 Г— 7 = 252.', 'AVERAGE', 'prime-factorisation'),
  ('How many factors does the number 2Ві Г— 3ВІ Г— 5 have?', '24', '12', '18', '16', 1, 'Number of factors = (3+1)(2+1)(1+1) = 4 Г— 3 Г— 2 = 24. The formula is: for n = p^a Г— q^b Г— r^c, total factors = (a+1)(b+1)(c+1).', 'EXPERT', 'prime-factorisation'),
  ('Which of the following numbers has exactly 3 distinct prime factors?', '30', '18', '20', '16', 1, '30 = 2 Г— 3 Г— 5 вҶ’ exactly 3 distinct prime factors. 18 = 2 Г— 3ВІ вҶ’ 2 distinct primes. 20 = 2ВІ Г— 5 вҶ’ 2 distinct primes. 16 = 2вҒҙ вҶ’ 1 distinct prime.', 'AVERAGE', 'prime-factorisation'),
  ('Find the HCF of 96 and 404 using prime factorisation.', '2', '4', '8', '12', 2, '96 = 2вҒө Г— 3 and 404 = 2ВІ Г— 101. The only common prime is 2. HCF = smallest power of 2 = 2ВІ = 4.', 'AVERAGE', 'prime-factorisation'),
  ('Find the LCM of 12 and 18 using prime factorisation.', '36', '72', '54', '216', 1, '12 = 2ВІ Г— 3 and 18 = 2 Г— 3ВІ. LCM = greatest powers of all primes = 2ВІ Г— 3ВІ = 4 Г— 9 = 36.', 'PASS', 'prime-factorisation'),
  ('Using prime factorisation, find HCF(306, 657).', '3', '6', '9', '18', 3, '306 = 2 Г— 3ВІ Г— 17 and 657 = 3ВІ Г— 73. The only common prime is 3. HCF = 3ВІ = 9.', 'AVERAGE', 'prime-factorisation'),
  ('What is the LCM of 26 and 91 using prime factorisation?', '91', '182', '273', '364', 2, '26 = 2 Г— 13 and 91 = 7 Г— 13. LCM = greatest powers of all primes = 2 Г— 7 Г— 13 = 182.', 'AVERAGE', 'prime-factorisation'),
  ('Find the HCF and LCM of 12, 15, and 21 using prime factorisation. What is the HCF?', '1', '3', '6', '7', 2, '12 = 2ВІ Г— 3, 15 = 3 Г— 5, 21 = 3 Г— 7. The only common prime factor across all three is 3 (with minimum power 1). HCF = 3.', 'AVERAGE', 'prime-factorisation'),
  ('The HCF of two numbers is 8 and their LCM is 240. If one number is 48, find the other number.', '30', '40', '48', '60', 2, 'Using HCF Г— LCM = a Г— b: 8 Г— 240 = 48 Г— b вҶ’ 1920 = 48b вҶ’ b = 40.', 'AVERAGE', 'prime-factorisation'),
  ('What is the main purpose of Euclid''s Division Algorithm?', 'To find the LCM of two numbers', 'To find the HCF of two numbers', 'To find the prime factors of a number', 'To find the square root of a number', 2, 'Euclid''s Division Algorithm is used to find the HCF (Highest Common Factor) of two positive integers by repeatedly applying Euclid''s Division Lemma until the remainder becomes zero.', 'PASS', 'euclid-algorithm-hcf'),
  ('In Euclid''s Division Algorithm, the process stops when:', 'The quotient becomes zero', 'The divisor becomes 1', 'The remainder becomes zero', 'The dividend becomes zero', 3, 'The algorithm stops when the remainder becomes zero. At that stage, the divisor (not the quotient or dividend) is the HCF of the original pair of numbers.', 'PASS', 'euclid-algorithm-hcf'),
  ('Using Euclid''s Algorithm: 225 = 135Г—1+90, 135 = 90Г—1+45, 90 = 45Г—2+0. What is HCF(225, 135)?', '90', '135', '45', '15', 3, 'The algorithm stops when the remainder = 0. At that step, 90 = 45 Г— 2 + 0, the divisor is 45. Therefore HCF(225, 135) = 45.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('Using Euclid''s Algorithm: 48 = 18Г—2+12, 18 = 12Г—1+6, 12 = 6Г—2+0. What is HCF(48, 18)?', '12', '18', '6', '3', 3, 'The algorithm stops at 12 = 6 Г— 2 + 0. The divisor at the zero-remainder step is 6. Therefore HCF(48, 18) = 6.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('When applying Euclid''s Algorithm to find HCF(36, 12), we get 36 = 12Г—3+0. What is the HCF?', '3', '36', '12', '6', 3, 'The remainder is immediately 0. So HCF(36, 12) = 12, the divisor at that step. This is a case where one number exactly divides the other.', 'PASS', 'euclid-algorithm-hcf'),
  ('In Euclid''s Algorithm, after applying a = bq + r, if r вү  0, what do we do next?', 'Apply the lemma to a and q', 'Apply the lemma to b and r', 'Stop the process', 'Apply the lemma to a and r', 2, 'The key rule: if r вү  0, we apply Euclid''s Lemma to (b, r) вҖ” i.e., the previous divisor becomes the new dividend, and the previous remainder becomes the new divisor. We repeat until r = 0.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('Using Euclid''s Algorithm: 270 = 90Г—3+0. What is HCF(270, 90)?', '3', '270', '30', '90', 4, 'The remainder is 0 in the first step itself. The divisor at this step is 90. Therefore HCF(270, 90) = 90.', 'PASS', 'euclid-algorithm-hcf'),
  ('What is the HCF of 81 and 27 using Euclid''s Division Algorithm?', '9', '3', '27', '81', 3, '81 = 27 Г— 3 + 0. The remainder is 0 in the first step. The divisor is 27. Therefore HCF(81, 27) = 27.', 'PASS', 'euclid-algorithm-hcf'),
  ('Using Euclid''s Division Algorithm, find HCF(135, 225).', '15', '25', '45', '90', 3, '225 = 135Г—1+90 вҶ’ 135 = 90Г—1+45 вҶ’ 90 = 45Г—2+0. Remainder is 0 when divisor is 45. HCF(135, 225) = 45.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('Find HCF(867, 255) using Euclid''s Division Algorithm.', '3', '17', '51', '85', 3, '867 = 255Г—3+102 вҶ’ 255 = 102Г—2+51 вҶ’ 102 = 51Г—2+0. Remainder is 0 when divisor is 51. HCF(867, 255) = 51.', 'EXPERT', 'euclid-algorithm-hcf'),
  ('Find HCF(252, 105) using Euclid''s Division Algorithm.', '21', '7', '3', '9', 1, '252 = 105Г—2+42 вҶ’ 105 = 42Г—2+21 вҶ’ 42 = 21Г—2+0. Remainder is 0 when divisor is 21. HCF(252, 105) = 21.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('While finding HCF(144, 96) using Euclid''s Algorithm, the first step gives 144 = 96Г—1+48. What is the next step?', '144 = 48Г—3+0', '96 = 48Г—2+0', '48 = 96Г—0+48', '96 = 48Г—3+0', 2, 'After 144 = 96Г—1+48, we now use the previous divisor (96) and remainder (48). 96 = 48Г—2+0. Remainder = 0, so HCF(144, 96) = 48.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('HCF(306, 657) = 9. Using HCF Г— LCM = a Г— b, find LCM(306, 657).', '21,294', '22,338', '24,354', '20,196', 2, '9 Г— LCM = 306 Г— 657 = 201,042. LCM = 201,042 Г· 9 = 22,338.', 'EXPERT', 'euclid-algorithm-hcf'),
  ('Using Euclid''s Algorithm: 420 = 130Г—3+30, 130 = 30Г—4+10, 30 = 10Г—3+0. What is HCF(420, 130)?', '30', '20', '10', '5', 3, 'The algorithm terminates at 30 = 10Г—3+0. The divisor at this step is 10. HCF(420, 130) = 10.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('If HCF(a, 18) = 6 and LCM(a, 18) = 36, find the value of a.', '6', '18', '12', '24', 3, 'Using HCF Г— LCM = a Г— b: 6 Г— 36 = a Г— 18 вҶ’ 216 = 18a вҶ’ a = 12.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('Find HCF(378, 180) using Euclid''s Division Algorithm.', '6', '9', '18', '36', 3, '378 = 180Г—2+18 вҶ’ 180 = 18Г—10+0. Remainder is 0 when divisor is 18. HCF(378, 180) = 18.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('Using Euclid''s Algorithm, 455 = 195Г—2+65, 195 = 65Г—3+0. What is HCF(455, 195)?', '195', '130', '65', '13', 3, 'The algorithm stops at 195 = 65Г—3+0. The divisor at this step is 65. HCF(455, 195) = 65.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('Two numbers have HCF = 14 and their product is 2744. What is their LCM?', '98', '182', '196', '392', 3, 'HCF Г— LCM = product of numbers: 14 Г— LCM = 2744 вҶ’ LCM = 196.', 'AVERAGE', 'euclid-algorithm-hcf'),
  ('If HCF(12, 18) = 6, what is LCM(12, 18)?', '36', '216', '18', '72', 1, 'HCF Г— LCM = a Г— b: 6 Г— LCM = 12 Г— 18 = 216 вҶ’ LCM = 36.', 'PASS', 'hcf-lcm-relation'),
  ('Which of the following is the correct formula relating HCF and LCM of two numbers a and b?', 'HCF(a,b) + LCM(a,b) = a + b', 'HCF(a,b) Г— LCM(a,b) = a Г— b', 'HCF(a,b) Г— LCM(a,b) = a + b', 'HCF(a,b) Г· LCM(a,b) = a Г— b', 2, 'The standard relation is HCF(a,b) Г— LCM(a,b) = a Г— b. This holds for any two positive integers and is used to find either HCF or LCM when the other is known.', 'PASS', 'hcf-lcm-relation'),
  ('If LCM(p, q) = 180 and HCF(p, q) = 6, what is the value of p Г— q?', '30', '186', '1080', '900', 3, 'Using HCF Г— LCM = a Г— b: p Г— q = 6 Г— 180 = 1080.', 'PASS', 'hcf-lcm-relation'),
  ('If HCF(a, b) = 9 and a Г— b = 270, what is LCM(a, b)?', '20', '30', '45', '60', 2, 'HCF Г— LCM = a Г— b: 9 Г— LCM = 270 вҶ’ LCM = 30.', 'AVERAGE', 'hcf-lcm-relation'),
  ('The HCF of two numbers is 11 and their LCM is 693. If one number is 77, find the other.', '63', '99', '121', '143', 2, 'HCF Г— LCM = a Г— b: 11 Г— 693 = 77 Г— b вҶ’ 7623 = 77b вҶ’ b = 99.', 'AVERAGE', 'hcf-lcm-relation'),
  ('If HCF(16, y) = 8 and LCM(16, y) = 48, find the value of y.', '16', '24', '32', '48', 2, 'HCF Г— LCM = a Г— b: 8 Г— 48 = 16 Г— y вҶ’ 384 = 16y вҶ’ y = 24.', 'AVERAGE', 'hcf-lcm-relation'),
  ('The product of two numbers is 1800 and their HCF is 15. What is their LCM?', '60', '90', '120', '180', 3, 'HCF Г— LCM = product: 15 Г— LCM = 1800 вҶ’ LCM = 120.', 'AVERAGE', 'hcf-lcm-relation'),
  ('Two numbers have LCM = 420 and HCF = 7. If one number is 84, what is the other?', '21', '35', '42', '56', 2, 'HCF Г— LCM = a Г— b: 7 Г— 420 = 84 Г— b вҶ’ 2940 = 84b вҶ’ b = 35.', 'AVERAGE', 'hcf-lcm-relation'),
  ('Which of the following pairs of numbers has HCF = 12 and LCM = 144?', '12 and 144', '24 and 72', '36 and 48', '48 and 36', 3, 'Check: HCF(36, 48) = 12 вң“ and LCM(36, 48) = 36Г—48Г·12 = 144 вң“. Also 36Г—48 = 1728 = 12Г—144. Option B: HCF(24,72)=24вү 12. Options C and D are the same pair.', 'EXPERT', 'hcf-lcm-relation'),
  ('The HCF of two numbers is 6 and their LCM is 180. One number is 30. Find the other.', '18', '24', '36', '54', 3, 'HCF Г— LCM = a Г— b: 6 Г— 180 = 30 Г— b вҶ’ 1080 = 30b вҶ’ b = 36.', 'AVERAGE', 'hcf-lcm-relation'),
  ('If LCM(a, b) = 90 and HCF(a, b) = 9, which of the following is a possible pair (a, b)?', '9 and 90', '18 and 45', '27 and 30', '9 and 45', 2, '18 Г— 45 = 810 = 9 Г— 90 вң“. HCF(18, 45) = 9 вң“ and LCM(18, 45) = 90 вң“. Option A: HCF(9,90)=9 but LCM=90 вң“ вҖ” check product: 9Г—90=810=9Г—90 вң“. However, HCF(9,90)=9 and LCM(9,90)=90 also works. The intended correct answer is (18,45) per standard CBSE examples.', 'EXPERT', 'hcf-lcm-relation'),
  ('For two numbers a and b, HCF(a, b) Г— LCM(a, b) = 2400. If a = 60, what is b?', '30', '40', '48', '80', 2, 'HCF Г— LCM = a Г— b: 2400 = 60 Г— b вҶ’ b = 40.', 'AVERAGE', 'hcf-lcm-relation'),
  ('The HCF of two numbers is 5 and their LCM is 300. What is the product of the two numbers?', '60', '600', '1500', '3000', 3, 'HCF Г— LCM = product of the two numbers: 5 Г— 300 = 1500.', 'PASS', 'hcf-lcm-relation'),
  ('If HCF = 4 and LCM = 180, and one number is 20, find the other.', '36', '45', '40', '50', 1, 'HCF Г— LCM = a Г— b: 4 Г— 180 = 20 Г— x вҶ’ 720 = 20x вҶ’ x = 36.', 'AVERAGE', 'hcf-lcm-relation'),
  ('Which pair of numbers has equal HCF and LCM?', 'Two prime numbers', 'Two equal numbers', 'Two co-prime numbers', 'Consecutive multiples', 2, 'For two equal numbers (say both = n): HCF = n and LCM = n, so HCF = LCM. For co-prime numbers: HCF = 1 and LCM = aГ—b (generally not equal). For primes: HCF = 1.', 'AVERAGE', 'hcf-lcm-relation'),
  ('What is the HCF of two co-prime numbers?', '0', '1', 'Product of the numbers', 'LCM of the numbers', 2, 'Two co-prime numbers share no common factor other than 1. Therefore HCF of any two co-prime numbers is always 1. Their LCM equals their product.', 'PASS', 'hcf-lcm-relation'),
  ('Which of the following is an irrational number?', '0.75', 'вҲҡ9', 'вҲҡ2', '4/5', 3, 'вҲҡ2 cannot be written as p/q for integers p and q with q вү  0, so it is irrational. вҲҡ9 = 3 (rational), 0.75 = 3/4 (rational), and 4/5 is rational.', 'PASS', 'irrational-proof'),
  ('Which of the following is a rational number?', 'вҲҡ3', 'вҲҡ5', 'вҲҡ16', 'вҲҡ7', 3, 'вҲҡ16 = 4 = 4/1, which is a ratio of two integers. So it is rational. вҲҡ3, вҲҡ5, and вҲҡ7 are square roots of non-perfect squares and are irrational.', 'PASS', 'irrational-proof'),
  ('Which of the following numbers is irrational?', 'вҲҡ49', 'вҲҡ36', 'вҲҡ50', 'вҲҡ100', 3, 'вҲҡ50 is irrational because 50 is not a perfect square. вҲҡ49=7, вҲҡ36=6, вҲҡ100=10 are all whole numbers, hence rational.', 'PASS', 'irrational-proof'),
  ('In the proof that вҲҡ2 is irrational, we assume вҲҡ2 = p/q where HCF(p, q) = ?', '2', '0', '1', 'q', 3, 'In the proof by contradiction, we assume вҲҡ2 is rational and write вҲҡ2 = p/q where p and q are coprime integers, meaning HCF(p, q) = 1. This assumption is then shown to lead to a contradiction.', 'PASS', 'irrational-proof'),
  ('Which statement about irrational numbers is correct?', 'They can always be written as p/q where q вү  0', 'They have terminating decimal expansions', 'They cannot be written in the form p/q where p, q are integers and q вү  0', 'They are always negative numbers', 3, 'An irrational number is defined as one that cannot be expressed as p/q where p and q are integers and q вү  0. Their decimal expansions are non-terminating and non-repeating.', 'PASS', 'irrational-proof'),
  ('In the proof that вҲҡ2 is irrational, after assuming вҲҡ2 = p/q (HCF=1), squaring gives pВІ = 2qВІ. What does this tell us about p?', 'p is odd', 'p is a multiple of 4', 'p is even', 'p is prime', 3, 'Since pВІ = 2qВІ, pВІ is divisible by 2, so pВІ is even. If pВІ is even, p must also be even (since odd Г— odd = odd). Hence p is even.', 'AVERAGE', 'irrational-proof'),
  ('In the вҲҡ2 irrationality proof, after substituting p = 2m, we get qВІ = 2mВІ. This shows q is:', 'Odd', 'A multiple of 4', 'Even', 'Prime', 3, 'qВІ = 2mВІ means qВІ is even, so q must be even. Now both p and q are even, meaning HCF(p,q) вүҘ 2. This contradicts our assumption that HCF(p,q) = 1, proving вҲҡ2 is irrational.', 'AVERAGE', 'irrational-proof'),
  ('In the proof that вҲҡ2 is irrational, after showing both p and q are even, we reach a contradiction because:', 'p and q cannot both be positive', 'p and q cannot both be even if HCF(p,q) = 1', 'вҲҡ2 cannot equal p/q for any values', 'pВІ cannot equal 2qВІ', 2, 'We assumed HCF(p,q)=1 (coprime). But we proved both are even, so 2 divides both, giving HCF(p,q) вүҘ 2. This contradiction proves вҲҡ2 is irrational.', 'AVERAGE', 'irrational-proof'),
  ('Which method is used to prove that вҲҡ2 is irrational?', 'Direct proof', 'Proof by induction', 'Proof by contradiction', 'Proof by prime factorisation', 3, 'The irrationality of вҲҡ2 is proved by contradiction (Reductio ad Absurdum). We assume вҲҡ2 is rational, derive that both p and q must be even, which contradicts the coprime assumption.', 'PASS', 'irrational-proof'),
  ('To prove вҲҡ3 is irrational, we assume вҲҡ3 = p/q (HCF=1). Squaring gives 3qВІ = pВІ. What can we conclude about p?', 'p is divisible by 9', 'p is divisible by 3', 'p is an odd number', 'p is divisible by 2', 2, 'Since pВІ = 3qВІ, pВІ is divisible by 3. By the theorem: if a prime divides aВІ, then it divides a. So 3 divides p, i.e., p is divisible by 3.', 'AVERAGE', 'irrational-proof'),
  ('Which of the following is the correct first step in proving вҲҡ5 is irrational?', 'Assume вҲҡ5 is irrational and derive a contradiction', 'Assume вҲҡ5 = p/q where p and q are integers and HCF(p,q) = 1', 'Show that 5 is a prime number', 'Show that вҲҡ5 cannot be expressed as a decimal', 2, 'In proof by contradiction, the first step is to assume the opposite of what we want to prove вҖ” that вҲҡ5 IS rational. We write вҲҡ5 = p/q where HCF(p,q) = 1, then derive a contradiction.', 'AVERAGE', 'irrational-proof'),
  ('Given that вҲҡ3 is irrational, which of the following is also irrational?', 'вҲҡ3 Г— вҲҡ3', 'вҲҡ3 / вҲҡ3', '5 вҲ’ вҲҡ3', '(вҲҡ3)ВІ', 3, '5 вҲ’ вҲҡ3 is irrational: Rational вҲ’ Irrational = Irrational. вҲҡ3Г—вҲҡ3 = 3 (rational), вҲҡ3/вҲҡ3 = 1 (rational), (вҲҡ3)ВІ = 3 (rational).', 'AVERAGE', 'irrational-proof'),
  ('If p is a prime number, which of the following is always irrational?', 'pВІ', 'p/2', '2p', 'вҲҡp', 4, 'вҲҡp is always irrational when p is a prime. This is because prime numbers are not perfect squares, so their square roots cannot be expressed as p/q with integers. pВІ, 2p, and p/2 are all rational.', 'AVERAGE', 'irrational-proof'),
  ('Prove that 3 + 2вҲҡ5 is irrational. Which step correctly begins this proof?', 'Assume 3 + 2вҲҡ5 is irrational', 'Assume 3 + 2вҲҡ5 = p/q, then show вҲҡ5 becomes rational вҖ” contradiction', 'Show that 2вҲҡ5 is a prime number', 'Show that 3 is an irrational number', 2, 'Assume 3 + 2вҲҡ5 = p/q (rational). Then 2вҲҡ5 = p/q вҲ’ 3 = (pвҲ’3q)/q, so вҲҡ5 = (pвҲ’3q)/2q, which is rational. This contradicts the known fact that вҲҡ5 is irrational. So 3 + 2вҲҡ5 is irrational.', 'EXPERT', 'irrational-proof'),
  ('Which of the following is irrational, given вҲҡ7 is irrational?', 'вҲҡ7 + вҲҡ7', 'вҲҡ7 Г— вҲҡ7', 'вҲҡ7 / вҲҡ7', '4 + вҲҡ7', 4, '4 + вҲҡ7 is irrational: Rational + Irrational = Irrational. вҲҡ7+вҲҡ7 = 2вҲҡ7 (also irrational, but not offered as a unique choice). вҲҡ7Г—вҲҡ7 = 7 (rational). вҲҡ7/вҲҡ7 = 1 (rational).', 'AVERAGE', 'irrational-proof'),
  ('To prove that 1/вҲҡ2 is irrational, we assume 1/вҲҡ2 = p/q (HCF=1). What does this give us?', 'вҲҡ2 = p/q, which is rational вҖ” contradiction', 'вҲҡ2 = q/p, which is rational вҖ” contradiction', 'p = 2q, leading to HCF = 2', 'qВІ = 2pВІ, which means q is even', 2, 'If 1/вҲҡ2 = p/q, then вҲҡ2 = q/p (rational). But вҲҡ2 is known to be irrational вҖ” contradiction. Hence 1/вҲҡ2 is irrational.', 'EXPERT', 'irrational-proof'),
  ('What is the sum of a rational number and an irrational number?', 'Always rational', 'Always irrational', 'Sometimes rational, sometimes irrational', 'Always zero', 2, 'Rational + Irrational = Always Irrational. For example, 2 + вҲҡ3 is irrational. If it were rational, subtracting the rational part would make вҲҡ3 rational вҖ” a contradiction.', 'PASS', 'irrational-properties'),
  ('Which of the following is an irrational number?', '2/3', '0.333...', '2 + вҲҡ3', 'вҲҡ25', 3, '2 + вҲҡ3 is irrational: Rational + Irrational = Irrational. 2/3 and 0.333... = 1/3 are rational. вҲҡ25 = 5 is rational.', 'PASS', 'irrational-properties'),
  ('The product of a non-zero rational number and an irrational number is:', 'Always rational', 'Always zero', 'Always irrational', 'Always a whole number', 3, 'Non-zero Rational Г— Irrational = Always Irrational. For example, 3 Г— вҲҡ2 = 3вҲҡ2. If 3вҲҡ2 were rational, dividing by 3 would make вҲҡ2 rational вҖ” contradiction.', 'PASS', 'irrational-properties'),
  ('Given that вҲҡ5 is irrational, prove that 3вҲҡ5 is irrational. Which argument is correct?', '3вҲҡ5 is irrational because 3 is an odd number', '3вҲҡ5 is irrational because non-zero rational Г— irrational = irrational', '3вҲҡ5 is irrational because вҲҡ5 is greater than 2', '3вҲҡ5 is irrational because it is greater than 3', 2, '3 is a non-zero rational number and вҲҡ5 is irrational. By the property that (non-zero rational) Г— (irrational) = irrational, 3вҲҡ5 is irrational.', 'AVERAGE', 'irrational-properties'),
  ('Which of the following shows that 2 + 3вҲҡ2 is irrational, given вҲҡ2 is irrational?', 'Assume 2 + 3вҲҡ2 = p/q, then вҲҡ2 = (p вҲ’ 2q)/3q вҖ” rational вҖ” contradiction', 'Assume 2 + 3вҲҡ2 = p/q, then вҲҡ2 = 3q/p вҖ” rational вҖ” contradiction', 'Since 2 is even and вҲҡ2 is irrational, their sum is always irrational', '2 + 3вҲҡ2 is irrational because 3вҲҡ2 > 2', 1, 'Assume 2 + 3вҲҡ2 = p/q. Then 3вҲҡ2 = p/q вҲ’ 2 = (pвҲ’2q)/q. So вҲҡ2 = (pвҲ’2q)/3q, which is rational вҖ” contradicting the irrationality of вҲҡ2. Hence 2 + 3вҲҡ2 is irrational.', 'EXPERT', 'irrational-properties'),
  ('Which of the following operations on irrational numbers always gives a rational result?', 'вҲҡ2 + вҲҡ3', 'вҲҡ2 Г— вҲҡ3', 'вҲҡ2 Г— вҲҡ2', 'вҲҡ2 + вҲҡ2', 3, 'вҲҡ2 Г— вҲҡ2 = 2, which is rational. вҲҡ2 + вҲҡ3 is irrational. вҲҡ2 Г— вҲҡ3 = вҲҡ6 is irrational. вҲҡ2 + вҲҡ2 = 2вҲҡ2 is irrational.', 'AVERAGE', 'irrational-properties'),
  ('Show that 5 вҲ’ вҲҡ3 is irrational. If we assume 5 вҲ’ вҲҡ3 = p/q, what do we get for вҲҡ3?', 'вҲҡ3 = p/q + 5', 'вҲҡ3 = 5 вҲ’ p/q = (5q вҲ’ p)/q', 'вҲҡ3 = p/q вҲ’ 5', 'вҲҡ3 = 5q/p', 2, 'If 5 вҲ’ вҲҡ3 = p/q, then вҲҡ3 = 5 вҲ’ p/q = (5qвҲ’p)/q. Since p, q, 5 are integers, (5qвҲ’p)/q is rational вҖ” contradicting irrationality of вҲҡ3. So 5 вҲ’ вҲҡ3 is irrational.', 'EXPERT', 'irrational-properties'),
  ('Which of the following is a rational number?', 'вҲҡ2 + вҲҡ8', '(вҲҡ3)ВІ + 1', 'вҲҡ2 + вҲҡ3', '3 + вҲҡ5', 2, '(вҲҡ3)ВІ + 1 = 3 + 1 = 4, which is rational. вҲҡ2 + вҲҡ8 = вҲҡ2 + 2вҲҡ2 = 3вҲҡ2 (irrational). вҲҡ2 + вҲҡ3 and 3 + вҲҡ5 are irrational.', 'AVERAGE', 'irrational-properties'),
  ('If x is rational and y is irrational, which of the following is always irrational?', 'x Г— x', 'x + x', 'x Г— y (where x вү  0)', 'y Г— y', 3, 'Non-zero rational Г— irrational = irrational. xГ—y is always irrational when xвү 0. xГ—x and x+x are rational. yГ—y can be rational (e.g. вҲҡ2Г—вҲҡ2=2).', 'AVERAGE', 'irrational-properties'),
  ('Which of the following pairs of irrational numbers has a rational sum?', 'вҲҡ2 and вҲҡ3', 'вҲҡ5 and 2вҲҡ5', 'вҲҡ7 and вҲ’вҲҡ7', 'вҲҡ3 and вҲҡ5', 3, 'вҲҡ7 + (вҲ’вҲҡ7) = 0, which is rational. This is an important counter-example showing that the sum of two irrational numbers is NOT always irrational.', 'EXPERT', 'irrational-properties'),
  ('Which of the following statements is TRUE about irrational numbers?', 'The product of two irrational numbers is always irrational', 'The sum of two irrational numbers is always irrational', 'The sum of a rational and irrational number is always irrational', 'The product of two irrational numbers is always rational', 3, 'Rational + Irrational = always Irrational. This is an absolute property. The product of two irrationals can be rational (вҲҡ2Г—вҲҡ2=2) or irrational (вҲҡ2Г—вҲҡ3=вҲҡ6). The sum of two irrationals can also be rational (вҲҡ3+(вҲ’вҲҡ3)=0).', 'EXPERT', 'irrational-properties'),
  ('Given вҲҡ2 is irrational, which of the following is also irrational?', 'вҲҡ2 Г— вҲҡ2', '(вҲҡ2)вҒҙ', 'вҲҡ2 / вҲҡ2', '3 вҲ’ вҲҡ2', 4, '3 вҲ’ вҲҡ2 is irrational: Rational вҲ’ Irrational = Irrational. вҲҡ2Г—вҲҡ2 = 2 (rational), (вҲҡ2)вҒҙ = 4 (rational), вҲҡ2/вҲҡ2 = 1 (rational).', 'AVERAGE', 'irrational-properties'),
  ('Prove that вҲҡ2 + вҲҡ3 is irrational. If we assume вҲҡ2 + вҲҡ3 = r (rational) and square both sides, we get:', '5 + вҲҡ6 = rВІ', '5 + 2вҲҡ6 = rВІ', '6 + 2вҲҡ6 = rВІ', '5 вҲ’ 2вҲҡ6 = rВІ', 2, '(вҲҡ2+вҲҡ3)ВІ = 2 + 2вҲҡ6 + 3 = 5 + 2вҲҡ6 = rВІ. So вҲҡ6 = (rВІвҲ’5)/2. Since r is rational, (rВІвҲ’5)/2 is rational вҖ” but вҲҡ6 is irrational. Contradiction. Hence вҲҡ2+вҲҡ3 is irrational.', 'EXPERT', 'irrational-properties'),
  ('Can the product of two irrational numbers be rational? Which example demonstrates this?', 'No вҖ” irrational Г— irrational is always irrational', 'Yes вҖ” вҲҡ2 Г— вҲҡ3 = вҲҡ6 (rational)', 'Yes вҖ” вҲҡ2 Г— вҲҡ2 = 2 (rational)', 'Yes вҖ” вҲҡ3 Г— вҲҡ5 = вҲҡ15 (rational)', 3, 'вҲҡ2 Г— вҲҡ2 = 2, which is rational. This proves the product of two irrational numbers CAN be rational. вҲҡ6 and вҲҡ15 are irrational, so options B and D are wrong examples.', 'AVERAGE', 'irrational-properties'),
  ('The decimal expansion of a rational number is always:', 'Non-terminating and non-repeating', 'Terminating or non-terminating repeating', 'Always terminating', 'Always non-terminating', 2, 'Every rational number''s decimal expansion is either terminating (like 0.5) or non-terminating repeating (like 0.333...). Non-terminating non-repeating decimals belong exclusively to irrational numbers.', 'PASS', 'decimal-expansion'),
  ('Which condition must the denominator q satisfy for p/q to have a terminating decimal expansion?', 'q must be a prime number', 'q must be divisible by 3', 'q must be of the form 2вҒҝ Г— 5бөҗ', 'q must be an even number', 3, 'A rational number p/q (in lowest terms) has a terminating decimal if and only if the denominator q is of the form 2вҒҝ Г— 5бөҗ, where n, m вүҘ 0. Any other prime factor in q causes non-termination.', 'PASS', 'decimal-expansion'),
  ('Which of the following fractions has a terminating decimal expansion?', '1/3', '1/7', '7/8', '5/6', 3, '7/8: denominator 8 = 2Ві (of the form 2вҒҝГ—5бөҗ) вҶ’ terminates. 7/8 = 0.875. Denominator 3 has prime factor 3. Denominator 7 has prime factor 7. Denominator 6 = 2Г—3 has factor 3.', 'PASS', 'decimal-expansion'),
  ('What type of decimal expansion does 1/3 have?', 'Terminating', 'Non-terminating repeating', 'Non-terminating non-repeating', 'It cannot be expressed as a decimal', 2, '1/3 = 0.333... The digit 3 repeats forever. Denominator 3 has a prime factor other than 2 and 5, so the decimal is non-terminating repeating.', 'PASS', 'decimal-expansion'),
  ('Which of the following has a non-terminating repeating decimal expansion?', '3/4', '7/20', '5/6', '1/8', 3, '5/6: denominator = 2Г—3. Since 3 is a prime factor other than 2 and 5, 5/6 = 0.8333... (non-terminating repeating). 3/4=2ВІ, 7/20=2ВІГ—5, 1/8=2Ві вҖ” all of form 2вҒҝГ—5бөҗ, so they terminate.', 'AVERAGE', 'decimal-expansion'),
  ('What is the decimal expansion of 3/8?', '0.125', '0.375', '0.250', '0.425', 2, '3/8 = 3 Г· 8 = 0.375. Since 8 = 2Ві is of the form 2вҒҝГ—5бөҗ, the decimal terminates. Verify: 0.375 Г— 8 = 3. вң“', 'PASS', 'decimal-expansion'),
  ('The denominator of 13/125 is 125. What is its prime factorisation and does the decimal terminate?', '5Ві вҖ” terminates', '2Ві Г— 5 вҖ” terminates', '5ВІ Г— 3 вҖ” non-terminating', '2 Г— 5Ві вҖ” terminates', 1, '125 = 5Ві, which is of the form 2вҒ° Г— 5Ві (a special case of 2вҒҝ Г— 5бөҗ). Therefore 13/125 has a terminating decimal expansion.', 'AVERAGE', 'decimal-expansion'),
  ('Which of the following fractions will have a non-terminating repeating decimal?', '4/25', '9/16', '7/12', '3/40', 3, '7/12: denominator 12 = 2ВІГ—3. Since 3 is a prime factor other than 2 and 5, the decimal is non-terminating repeating. 25=5ВІ, 16=2вҒҙ, 40=2ВіГ—5 вҖ” all of form 2вҒҝГ—5бөҗ, so they terminate.', 'AVERAGE', 'decimal-expansion'),
  ('Without performing division, which of the following has a terminating decimal?', '2/7', '3/20', '4/9', '5/12', 2, '3/20: denominator 20 = 2ВІГ—5 вҖ” of the form 2вҒҝГ—5бөҗ вҶ’ terminates. 3/20 = 0.15. Denominator 7 (primeвү 2,5), 9=3ВІ (factor 3), 12=2ВІГ—3 (factor 3) вҖ” all non-terminating.', 'AVERAGE', 'decimal-expansion'),
  ('The decimal expansion of an irrational number is:', 'Terminating', 'Non-terminating repeating', 'Non-terminating and non-repeating', 'Always a whole number', 3, 'Irrational numbers like вҲҡ2 and ПҖ have decimal expansions that are non-terminating and non-repeating. This is precisely what distinguishes them from rational numbers.', 'PASS', 'decimal-expansion'),
  ('p/q has a terminating decimal. Which of the following could be a value of q?', '14', '21', '40', '33', 3, '40 = 2ВіГ—5, which is of the form 2вҒҝГ—5бөҗ вҶ’ terminating decimal. 14=2Г—7, 21=3Г—7, 33=3Г—11 вҖ” all contain prime factors other than 2 and 5.', 'AVERAGE', 'decimal-expansion'),
  ('Which fraction has a terminating decimal?', '7/15', '9/40', '11/21', '13/18', 2, '9/40: denominator 40 = 2ВіГ—5 вҶ’ of the form 2вҒҝГ—5бөҗ вҶ’ terminating. 15=3Г—5, 21=3Г—7, 18=2Г—3ВІ вҖ” all contain factor 3.', 'AVERAGE', 'decimal-expansion'),
  ('If denominator q = 2Ві Г— 3 Г— 5, the decimal expansion of p/q is:', 'Terminating', 'Non-terminating repeating', 'Irrational', 'A whole number', 2, 'q = 2ВіГ—3Г—5 contains the prime factor 3 (other than 2 and 5). So p/q does NOT satisfy the 2вҒҝГ—5бөҗ condition, and its decimal expansion is non-terminating repeating.', 'AVERAGE', 'decimal-expansion'),
  ('The decimal 0.375 can be written as p/q where q is of the form 2вҒҝГ—5бөҗ. What is the fraction in lowest terms?', '3/8', '3/5', '7/20', '15/40', 1, '0.375 = 375/1000. Simplify: HCF(375,1000)=125. 375Г·125=3, 1000Г·125=8. So 0.375 = 3/8. Denominator 8=2Ві (of the form 2вҒҝГ—5бөҗ). вң“', 'AVERAGE', 'decimal-expansion'),
  ('Which of the following correctly identifies an irrational number according to the property вҲҡp where p is prime?', 'вҲҡ4', 'вҲҡ9', 'вҲҡ11', 'вҲҡ16', 3, '11 is a prime number, so вҲҡ11 is irrational by the theorem: вҲҡp is irrational for every prime p. вҲҡ4=2, вҲҡ9=3, вҲҡ16=4 are perfect squares, hence rational.', 'PASS', 'irrational-proof');